@Documented
@Constraint(validatedBy=ValidTickerValidator.class)
@Target({ElementType.FIELD,ElementType.PARAMETER})
@Retention(RetentionPolicy.RUNTIME)
@interface ValidTicker {
    String message() default "Invalid stock ticker symbol";
    Class<?>[] groups() default {};
    Class<? extends Payload>[] payload() default {};
}

class ValidTickerValidator implements ConstraintValidator<ValidTicker,String> {
    private static final Set<String> NSE_SYMBOLS=Set.of(
        "RELIANCE","TCS","INFY","HDFCBANK","ICICIBANK","WIPRO","AXISBANK");
    @Override
    public boolean isValid(String value, ConstraintValidatorContext ctx){
        if(value==null||value.isBlank()) return false;
        return NSE_SYMBOLS.contains(value.toUpperCase());
    }
}

record OrderRequest(
    @ValidTicker String symbol,
    @jakarta.validation.constraints.Positive int quantity
){}

