    }
    @Test void invalidSymbol_fails(){
        var req=new OrderRequest("FAKE_SYMBOL",10);
        var violations=validator.validate(req);
        assertFalse(violations.isEmpty());
        assertEquals("Invalid stock ticker symbol",violations.iterator().next().getMessage());
    }
}

