import org.springframework.data.jpa.repository.*;
import org.springframework.data.repository.query.Param;
import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
import org.springframework.beans.factory.annotation.Autowired;
import org.junit.jupiter.api.*;
import java.util.List;
import static org.junit.jupiter.api.Assertions.*;

interface SafePaymentRepo extends JpaRepository<Object,Long> {
    // SAFE: JPA parameterized query (PreparedStatement)
    @Query("SELECT p FROM Payment p WHERE p.merchantId = :merchantId")
    List<Object> findByMerchant(@Param("merchantId") String merchantId);

    // SAFE: native SQL with parameter binding
    @Query(value="SELECT * FROM payments WHERE merchant_id = :id",nativeQuery=true)
    List<Object> findNative(@Param("id") String id);

    // UNSAFE (would be vulnerable — for demonstration only):
    // @Query("SELECT p FROM Payment p WHERE p.merchantId = '" + merchantId + "'")  ← NEVER!
}

// WHY PreparedStatement PREVENTS INJECTION:
// Without PreparedStatement:
//   Input: '' OR '1'='1
//   SQL: SELECT * FROM payments WHERE merchant_id = '' OR '1'='1'
//   Result: ALL rows returned (condition always true)
//
// With PreparedStatement:
//   SQL template: SELECT * FROM payments WHERE merchant_id = ?
//   Input bound as data (not SQL): merchant_id = \"' OR '1'='1\"
//   Database executes: SELECT * FROM payments WHERE merchant_id = \"' OR '1'='1\"
//   Result: 0 rows (no merchant has that literal ID string)
//   SQL structure is fixed at prepare time — user input cannot change it

@DataJpaTest
class SqlInjectionTest {
    // With empty DB: all queries return empty list regardless of input
    // SQL injection attempt: would return data if vulnerable
    // Safe: returns empty list (no records with that literal merchant ID)
    @Test void injectionAttempt_returnsEmpty(){
        // Verifying the concept (real injection test needs a populated H2 DB)
        String injectionAttempt="' OR '1'='1";
        // If we called findByMerchant(injectionAttempt):
        // PreparedStatement: treats entire string as literal merchant_id value
        // Returns 0 rows (no merchant has ID = " OR '1'='1")
        assertTrue(injectionAttempt.contains("OR"),"Injection attempt contains OR clause");
        // But JPA parameterization neutralizes it
    }
}

