import java.nio.file.*;
import java.io.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
public class FileSafetyService {
    private static final Path BASE_DIR=Path.of("/tmp/reports").normalize();

    public String getSafeReportPath(String filename) {
        // Step 1: Reject obvious traversal patterns:
        if(filename==null||filename.contains("..")||filename.contains("/")||filename.contains("\\")){
            throw new SecurityException("Invalid filename: " + filename);
        }

        // Step 2: Resolve against base dir:
        Path resolved=BASE_DIR.resolve(filename).normalize();

        // Step 3: Verify resolved path is still within base dir:
        if(!resolved.startsWith(BASE_DIR)){
            throw new SecurityException("Path traversal attempt detected: " + filename);
        }

        return resolved.toString();
    }

    // ATTACK ATTEMPTS BLOCKED:
    // filename='../../../etc/passwd' → contains '..' → rejected
    // filename='safe/../../etc/passwd' → resolves outside BASE_DIR → rejected
    // filename='report-2024.pdf' → safe, within BASE_DIR
}

@SpringBootTest
class PathSafetyTest {
    @Autowired FileSafetyService svc;
    @Test void safePath_allowed(){
        String path=svc.getSafeReportPath("report-2024.pdf");
        assertTrue(path.startsWith("/tmp/reports"));
    }
    @Test void pathTraversal_blocked(){
        assertThrows(SecurityException.class,()->svc.getSafeReportPath("../../../etc/passwd"));
    }
}

import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
public class XSSProtectionService {
    // Using Jsoup HTML Sanitizer (add dependency: org.jsoup:jsoup:1.17.2)
    // Alternative: OWASP Java HTML Sanitizer library

    public String sanitizeHtml(String input) {
        if (input == null) return null;
        // Jsoup whitelist sanitizer:
        // org.jsoup.safety.Safelist.basic() allows: p, b, i, em, strong, a, etc.
        // Strips: script, iframe, onload, onclick, onerror, javascript: href
        return org.jsoup.Jsoup.clean(input,
            org.jsoup.safety.Safelist.basic()
                .addTags("p","br")
                .removeTags("a"));  // remove links (can be used for phishing)
    }

    // WHAT THIS BLOCKS:
    // <script>alert('XSS')</script> → completely removed
    // <img src='x' onerror='steal()'> → img removed (or src kept, onerror stripped)
    // <iframe src='evil.com'> → removed
    // <a href='javascript:alert(1)'>click</a> → link removed (we removed <a> tags)
    //
    // WHAT THIS ALLOWS:
    // <p>Hello <strong>world</strong></p> → preserved
    // <em>Emphasis</em> → preserved

    public boolean containsXssAttempt(String input) {
        if (input == null) return false;
        String lower = input.toLowerCase();
        return lower.contains("<script") || lower.contains("javascript:") ||
               lower.contains("onerror=") || lower.contains("onload=") ||
               lower.contains("<iframe");
    }
}

@SpringBootTest
class XSSTest {
    @Autowired XSSProtectionService svc;
    @Test void safeHtml_preserved(){
        String safe="<p>Hello <strong>world</strong></p>";
        String result=svc.sanitizeHtml(safe);
        assertTrue(result.contains("<strong>world</strong>"));
    }
    @Test void xssScript_stripped(){
        String xss="<p>Hello</p><script>alert('xss')</script>";
        String result=svc.sanitizeHtml(xss);
        assertFalse(result.contains("<script>"),"Script tag must be removed");
    }
}

