import org.springframework.context.annotation.*;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.*;
import org.springframework.security.web.csrf.CookieCsrfTokenRepository;
import org.springframework.boot.test.context.SpringBootTest;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

// WHEN TO ENABLE/DISABLE CSRF:
// ENABLE CSRF for:
//   - Web forms (HTML + sessions): browser auto-submits cookies → CSRF attacks possible
//   - Any stateful endpoint using session cookies
//   - Thymeleaf/JSP forms: Spring Security auto-includes CSRF token
//
// DISABLE CSRF for:
//   - Stateless REST APIs using JWT: no session cookie → CSRF not possible
//   - Mobile apps: use Authorization header (not cookies) → CSRF not possible
//   - Microservice-to-microservice: no browser involved
//
// Rule: if the client stores auth in a COOKIE → enable CSRF
//        if the client uses Authorization header (JWT) → can disable CSRF

@Configuration @EnableWebSecurity
class MixedSecurityConfig {
    @Bean SecurityFilterChain chain(HttpSecurity h) throws Exception {
        return h
            // For web dashboard (session + CSRF):
            .csrf(csrf->csrf
                .csrfTokenRepository(CookieCsrfTokenRepository.withHttpOnlyFalse())
                // CookieCsrfTokenRepository: CSRF token in cookie (readable by JS)
                // Angular/React can read cookie and include in X-XSRF-TOKEN header
                .ignoringRequestMatchers("/api/**")  // REST API endpoints: no CSRF (JWT auth)
            )
            .authorizeHttpRequests(a->a
                .requestMatchers("/dashboard/**").authenticated()  // uses session
                .requestMatchers("/api/**").authenticated()        // uses JWT
                .anyRequest().permitAll())
            .build();
    }
}

@SpringBootTest
class CsrfConfigTest {
    @Test void csrfConfigIsCorrect(){
        // CSRF enabled for web, disabled for API:
        assertTrue(CookieCsrfTokenRepository.class.getSimpleName().contains("Cookie"));
        System.out.println("CSRF: enabled for web forms, disabled for JWT REST API");
    }
}

