            .oauth2ResourceServer(o->o.jwt(j->{})).build();
    }
}

@Service class SynthFileSafety {
    Path BASE=Path.of("/tmp").normalize();
    String safe(String f){
        if(f==null||f.contains("..")) throw new SecurityException("unsafe: "+f);
        return BASE.resolve(f).normalize().toString();
    }
}

